  const [status, setStatus] = useState<ShiftStatus>('offline');
  const [elapsedTime, setElapsedTime] = useState(0);
  const [earningsToday, setEarningsToday] = useState(124.50);

  // Timer logic for "Online" status
  useEffect(() => {
    let interval: number | undefined;

    if (status === 'online') {
      interval = window.setInterval(() => {
        setElapsedTime(prev => prev + 1);
      }, 1000);
    } else {
      clearInterval(interval);
    }

    return () => clearInterval(interval);
  }, [status]);

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const handleStatusChange = (newStatus: ShiftStatus) => {
    setStatus(newStatus);
    // Logic for starting/stopping shifts would go here
    if (newStatus === 'offline') {
      // Logic to save shift data
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900">

      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/20 z-20 lg:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
