        w-64 bg-white border-r border-slate-200 transform transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col">
          <div className="h-20 flex items-center px-8 border-b border-slate-100">
            <div className="w-8 h-8 bg-black rounded-lg mr-3 flex items-center justify-center">
              <span className="text-white font-bold text-sm">DD</span>
            </div>
            <h1 className="text-lg font-bold tracking-tight">Dashboard Driver</h1>
          </div>

          <nav className="flex-1 px-4 py-6 space-y-1">
            <NavItem icon={<LayoutDashboard size={20} />} label="Overview" active />
            <NavItem icon={<Wallet size={20} />} label="Earnings" />
            <NavItem icon={<Clock size={20} />} label="History" />
            <NavItem icon={<Settings size={20} />} label="Settings" />
          </nav>

          <div className="p-4 border-t border-slate-100">
            <div className="flex items-center p-3 rounded-lg bg-slate-50 border border-slate-100">
              <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center text-slate-500 font-medium">
                JD
              </div>
              <div className="ml-3">
                <p className="text-sm font-medium">John Doe</p>
                <p className="text-xs text-slate-500">Pro Driver</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
