            <input 
              type="date" 
              className="w-full text-xs p-2 bg-slate-100 rounded-lg border-0"
              value={customRange?.end || ''}
              onChange={(e) => onCustomRangeChange && onCustomRangeChange(customRange?.start || '', e.target.value)}
            />
