  );
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Settings, 
  LogOut,
  CalendarCheck,
  TrendingUp,
  MapPin,
  RefreshCw,
  Clock,
  UserCircle
} from 'lucide-react';
import { SmartCard, FilterType } from './components/SmartCard'; // New Smart Component
