import { AustriaControls } from './components/AustriaControls';
import { DailyLog } from './components/DailyLog';
import { SettingsView } from './components/SettingsView';
import { ProfileView } from './components/ProfileView'; // New
import { BottomNav } from './components/BottomNav';
import { Auth } from './components/Auth';
import { formatCurrency, formatDuration } from './utils/formatters';

type ViewType = 'dashboard' | 'history' | 'settings' | 'profile';

const App: React.FC = () => {
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [username, setUsername] = useState<string>(localStorage.getItem('username') || 'Driver');
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  // Data State
  const [ratePerKm, setRatePerKm] = useState(0.12);
  const [logs, setLogs] = useState<any[]>([]);
  const [austriaLogs, setAustriaLogs] = useState<any[]>([]); // Daily Aggregates
  const [austriaSessions, setAustriaSessions] = useState<any[]>([]); // Detailed History

  // Austria Live State
  const [austriaState, setAustriaState] = useState({
    total_seconds: 0,
    is_active: false,
    last_start_timestamp: null as number | null
  });

  // Timers
  const [currentSessionSeconds, setCurrentSessionSeconds] = useState(0);

  // --- FILTERS STATE ---
  const [earningsFilter, setEarningsFilter] = useState<FilterType>('today');
  const [earningsCustomRange, setEarningsCustomRange] = useState({ start: '', end: '' });

  const [austriaFilter, setAustriaFilter] = useState<FilterType>('today');
  const [austriaCustomRange, setAustriaCustomRange] = useState({ start: '', end: '' });

  // Auth Handler
  const handleLogin = (newToken: string, user: string) => {
    localStorage.setItem('token', newToken);
    localStorage.setItem('username', user);
    setToken(newToken);
    setUsername(user);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('username');
    setToken(null);
  };

  // Fetch Data
  const fetchData = async () => {
    if (!token) return;
    setIsLoading(true);
    try {
      const res = await fetch('/api/data', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.status === 401 || res.status === 403) {
        handleLogout();
        return;
      }
      const data = await res.json();
      setRatePerKm(data.settings.rate_per_km);
      setLogs(data.logs);
      setAustriaLogs(data.austria_logs || []); 
      setAustriaSessions(data.austria_sessions || []); 
      setAustriaState(data.austria);

      // Calculate initial session time
      if (data.austria.is_active && data.austria.last_start_timestamp) {
        setCurrentSessionSeconds(Math.floor((Date.now() - data.austria.last_start_timestamp) / 1000));
      } else {
        setCurrentSessionSeconds(0);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  // Initial Load
  useEffect(() => {
    if (token) fetchData();
  }, [token]);

  // Austria Timer Tick
  useEffect(() => {
    let interval: number;
    if (austriaState.is_active && austriaState.last_start_timestamp) {
      interval = window.setInterval(() => {
        // Just measure start to now
        setCurrentSessionSeconds(Math.floor((Date.now() - (austriaState.last_start_timestamp as number)) / 1000));
      }, 1000);
    } else {
      setCurrentSessionSeconds(0);
    }
    return () => clearInterval(interval);
  }, [austriaState]);

  // Actions
  const updateSettings = async (newRate: number) => {
    try {
      await fetch('/api/settings', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({ rate_per_km: newRate })
      });
      setRatePerKm(newRate);
    } catch (err) {
      console.error(err);
    }
  };

  const toggleAustria = async () => {
    try {
      const res = await fetch('/api/austria/toggle', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      setAustriaState({
        total_seconds: data.total_seconds,
        is_active: data.is_active,
        last_start_timestamp: data.is_active ? Date.now() : null
      });

      if (!data.is_active) {
        setCurrentSessionSeconds(0);
      }

      // Force refresh of history immediately
      setTimeout(fetchData, 100); 

    } catch (err) {
      console.error(err);
    }
  };

  const handleDailyLogSave = async (data: any) => {
     try {
       await fetch('/api/logs', {
         method: 'POST',
         headers: { 
           'Content-Type': 'application/json', 
           'Authorization': `Bearer ${token}`
         },
         body: JSON.stringify({
             date: new Date().toISOString().split('T')[0],
             ...data 
         })
       });
       fetchData();
     } catch (err) {
       console.error("Failed to save");
       throw err;
     }
  };

  const handleLogUpdate = async (updatedLog: any) => {
    try {
       const dist = Math.max(0, updatedLog.end_km - updatedLog.start_km);
       const newTotal = (dist * ratePerKm) + updatedLog.wage;

       await fetch('/api/logs', {
         method: 'POST',
         headers: { 
           'Content-Type': 'application/json', 
           'Authorization': `Bearer ${token}`
         },
         body: JSON.stringify({
           ...updatedLog,
           total_earnings: newTotal
         })
       });
       fetchData();
    } catch (err) {
      alert('Failed to update log');
    }
  };

  // --- CALCULATION HELPERS ---

  const isDateInMonth = (dateStr: string) => {
    const d = new Date(dateStr);
    const now = new Date();
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  };

  const isDateInRange = (dateStr: string, start: string, end: string) => {
    if (!start || !end) return false;
    const d = new Date(dateStr).getTime();
    const s = new Date(start).getTime();
    const e = new Date(end).getTime();
    return d >= s && d <= e;
  };

  const isToday = (dateStr: string) => {
    return dateStr === new Date().toISOString().split('T')[0];
  }

  // Calculate Displayed Earnings based on Filter
  const getDisplayedEarnings = () => {
    if (earningsFilter === 'today') {
      const todayLog = logs.find(l => isToday(l.date));
      return todayLog ? todayLog.total_earnings : 0;
    } 
    else if (earningsFilter === 'month') {
      return logs
        .filter(l => isDateInMonth(l.date))
        .reduce((sum, l) => sum + l.total_earnings, 0);
    } 
    else if (earningsFilter === 'custom') {
      return logs
        .filter(l => isDateInRange(l.date, earningsCustomRange.start, earningsCustomRange.end))
        .reduce((sum, l) => sum + l.total_earnings, 0);
    }
    return 0;
  };

  // Calculate Displayed Austria Time (TOTAL) based on Filter
  const getDisplayedAustriaTime = () => {
    const todayStr = new Date().toISOString().split('T')[0];

    if (austriaFilter === 'today') {
        // Today = stored total + current session if active
        return austriaState.total_seconds + currentSessionSeconds;
    }

    // Historical sum (excluding today to allow live update)
    const historicalSum = austriaLogs
      .filter(log => {
        if (log.date === todayStr) return false;
        if (austriaFilter === 'month') return isDateInMonth(log.date);
        if (austriaFilter === 'custom') return isDateInRange(log.date, austriaCustomRange.start, austriaCustomRange.end);
        return false;
      })
      .reduce((acc, curr) => acc + curr.total_seconds, 0);

    let addToday = false;
    if (austriaFilter === 'month') addToday = true;
    if (austriaFilter === 'custom') addToday = isDateInRange(todayStr, austriaCustomRange.start, austriaCustomRange.end);

    return historicalSum + (addToday ? (austriaState.total_seconds + currentSessionSeconds) : 0);
  };

  if (!token) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900 pb-20 lg:pb-0">

      {/* Sidebar Navigation (Desktop) */}
      <aside className="hidden lg:flex fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white flex-col shadow-2xl">
        <div className="h-24 flex items-center px-8 border-b border-slate-800">
           <div>
             <h1 className="text-2xl font-black tracking-tighter text-white">MASTNAK</h1>
             <p className="text-xs text-slate-400 font-medium tracking-widest uppercase">Driver Intelligence</p>
           </div>
        </div>

        <nav className="flex-1 px-4 py-8 space-y-2">
          <NavItem 
            icon={<LayoutDashboard size={20} />} 
            label="Dashboard" 
            active={currentView === 'dashboard'} 
            onClick={() => setCurrentView('dashboard')}
          />
          <NavItem 
            icon={<Wallet size={20} />} 
            label="History" 
            active={currentView === 'history'} 
            onClick={() => setCurrentView('history')}
          />
          <NavItem 
            icon={<Settings size={20} />} 
            label="Settings" 
            active={currentView === 'settings'} 
            onClick={() => setCurrentView('settings')}
          />
        </nav>

        <div className="p-6 border-t border-slate-800 bg-slate-900/50">
          <button 
             onClick={() => setCurrentView('profile')}
             className="flex items-center gap-3 mb-4 w-full hover:bg-slate-800 p-2 rounded-xl transition-colors text-left"
          >
             <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold text-lg shadow-lg">
                {username.charAt(0).toUpperCase()}
             </div>
             <div>
                <p className="font-bold text-sm text-white">{username}</p>
                <p className="text-xs text-slate-400">View Profile</p>
             </div>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:ml-64">
        {/* Header */}
        <header className="h-16 lg:h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 flex items-center justify-between px-4 lg:px-10 shrink-0 sticky top-0 z-20">
          <div className="flex items-center gap-3">
             <div className="lg:hidden w-8 h-8 bg-slate-900 rounded-lg flex items-center justify-center text-white font-bold text-xs">M</div>
             <h2 className="text-lg lg:text-xl font-bold text-slate-800">
               {currentView === 'dashboard' ? 'Overview' : 
                currentView === 'history' ? 'History' : 
                currentView === 'profile' ? 'My Profile' :
                'Settings'}
             </h2>
          </div>

          {currentView !== 'profile' && (
            <div className="flex items-center space-x-4">
               <button onClick={fetchData} className="p-2 text-slate-400 hover:text-slate-900 transition-colors rounded-full hover:bg-slate-100">
                 <RefreshCw size={20} className={isLoading ? "animate-spin" : ""} />
               </button>
               <div className="hidden md:flex items-center gap-2 text-sm font-bold text-slate-600 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 shadow-sm">
                  <CalendarCheck size={16} className="text-indigo-500" />
                  <span>{new Date().toLocaleDateString('de-DE', { weekday: 'short', day: '2-digit', month: 'long' })}</span>
               </div>
            </div>
          )}
        </header>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-auto p-4 lg:p-8 scrollbar-hide">
          <div className="max-w-7xl mx-auto space-y-6 pb-24">

            {currentView === 'dashboard' && (
              <>
                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {/* CONSOLIDATED EARNINGS CARD */}
                  <SmartCard 
                    title="Earnings" 
                    value={formatCurrency(getDisplayedEarnings())}
                    icon={<Wallet className="text-indigo-600" />}
                    filterType={earningsFilter}
                    onFilterChange={setEarningsFilter}
                    customRange={earningsCustomRange}
                    onCustomRangeChange={(s, e) => setEarningsCustomRange({ start: s, end: e })}
                    trend="Calculated based on logs"
                    trendUp={true}
                  />

                  {/* CONSOLIDATED AUSTRIA CARD (SHOWS TOTAL) */}
                  <SmartCard 
                    title="Time in Austria" 
                    value={formatDuration(getDisplayedAustriaTime())}
                    icon={<Clock className="text-rose-600" />}
                    filterType={austriaFilter}
                    onFilterChange={setAustriaFilter}
                    customRange={austriaCustomRange}
                    onCustomRangeChange={(s, e) => setAustriaCustomRange({ start: s, end: e })}
                    subtitle={austriaState.is_active ? "Tracking Currently Active" : "Tracking Paused"}
                  />

                  <StatCard 
                    title="Current Rate" 
                    value={`${formatCurrency(ratePerKm)}/km`} 
                    icon={<MapPin className="text-emerald-600" />}
                    subtitle="Configuration"
                  />
                </div>

                <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                  {/* Left Column: Chart & Activity */}
                  <div className="xl:col-span-2 space-y-6">
                     <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                       <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                         <TrendingUp size={20} className="text-slate-400" />
                         Revenue Analytics
                       </h3>
                       <div className="h-[280px] w-full">
                         <RevenueChart data={logs} />
                       </div>
                     </div>
                  </div>

                  {/* Right Column: Controls */}
                  <div className="flex flex-col gap-6">
                    {/* CONTROLS CARD (SHOWS SESSION TIME) */}
                    <AustriaControls 
                      isInsideAustria={austriaState.is_active}
                      currentSessionTime={currentSessionSeconds} 
                      onToggle={toggleAustria}
                    />

                    <DailyLog ratePerKm={ratePerKm} onSave={handleDailyLogSave} />
                  </div>
                </div>
              </>
            )}

            {currentView === 'history' && (
               <RecentActivity 
                 logs={logs} 
                 austriaSessions={austriaSessions} 
                 onUpdateLog={handleLogUpdate}
               />
            )}

            {currentView === 'settings' && (
              <SettingsView ratePerKm={ratePerKm} setRatePerKm={updateSettings} />
            )}

            {currentView === 'profile' && (
              <ProfileView 
                username={username} 
                ratePerKm={ratePerKm} 
                onLogout={handleLogout}
                onBack={() => setCurrentView('dashboard')}
              />
            )}
          </div>
        </div>
      </main>

      <BottomNav currentView={currentView} onChangeView={setCurrentView} username={username} />
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode; label: string; active?: boolean; onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`
    w-full flex items-center space-x-3 px-4 py-3 rounded-xl text-sm font-bold transition-all duration-200
    ${active 
      ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
      : 'text-slate-400 hover:bg-slate-800 hover:text-white'}
  `}>
    {icon}
    <span>{label}</span>
  </button>
);

export default App;

const express = require('express');
const sqlite3 = require('sqlite3').verbose();
const cors = require('cors');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const path = require('path');
const fs = require('fs');
const os = require('os');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET_KEY = "dashboard_driver_secret_key_change_in_prod";

// Middleware
app.use(cors());
app.use(express.json());

// Serve static files from dist
const distPath = path.join(__dirname, 'dist');
if (fs.existsSync(distPath)) {
  app.use(express.static(distPath));
} else {
  console.warn("WARNING: 'dist' folder not found. Run 'npm run build' to generate frontend assets.");
}

// Database Setup
const dbDataDir = path.join(__dirname, 'data');
if (!fs.existsSync(dbDataDir)){
    fs.mkdirSync(dbDataDir);
}
const db = new sqlite3.Database(path.join(dbDataDir, 'driver.db'));

db.serialize(() => {
  // Users Table
  db.run(`CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE,
    password TEXT,
    rate_per_km REAL DEFAULT 0.12,
    language TEXT DEFAULT 'en'
  )`);

  // Migration for language column if it doesn't exist (Simple check)
  db.all("PRAGMA table_info(users)", (err, rows) => {
    if (!rows.some(col => col.name === 'language')) {
      db.run("ALTER TABLE users ADD COLUMN language TEXT DEFAULT 'en'");
    }
  });

  // Daily Logs (Earnings)
  db.run(`CREATE TABLE IF NOT EXISTS daily_logs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    date TEXT,
    start_km REAL,
    end_km REAL,
    wage REAL,
    total_earnings REAL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  // Austria Daily Aggregates
  db.run(`CREATE TABLE IF NOT EXISTS austria_logs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    date TEXT,
    total_seconds INTEGER DEFAULT 0,
    is_active INTEGER DEFAULT 0, 
    last_start_timestamp INTEGER
  )`);

  // Austria Sessions
  db.run(`CREATE TABLE IF NOT EXISTS austria_sessions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    start_time INTEGER,
    end_time INTEGER,
    duration INTEGER,
    date TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  // Notes / Reminders
  db.run(`CREATE TABLE IF NOT EXISTS notes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    content TEXT,
    reminder_date TEXT,
    is_completed INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);
});

// --- Auth Middleware ---
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// --- Routes ---

// Health Check
app.get('/health', (req, res) => {
  res.status(200).send('OK');
});

// Register
app.post('/api/auth/register', async (req, res) => {
  const { username, password } = req.body;
  const hashedPassword = await bcrypt.hash(password, 10);

  db.run(`INSERT INTO users (username, password) VALUES (?, ?)`, [username, hashedPassword], function(err) {
    if (err) return res.status(400).json({ error: "Username already exists" });
    res.json({ message: "User created" });
  });
});

// Login
app.post('/api/auth/login', (req, res) => {
  const { username, password } = req.body;
  db.get(`SELECT * FROM users WHERE username = ?`, [username], async (err, user) => {
    if (err || !user) return res.status(400).json({ error: "User not found" });

    if (await bcrypt.compare(password, user.password)) {
      const token = jwt.sign({ id: user.id, username: user.username }, SECRET_KEY);
      res.json({ token, rate_per_km: user.rate_per_km, username: user.username, language: user.language || 'en' });
    } else {
      res.status(403).json({ error: "Invalid password" });
    }
  });
});

// Get Dashboard Data
app.get('/api/data', authenticateToken, (req, res) => {
  const today = new Date().toISOString().split('T')[0];
  const userId = req.user.id;

  const response = {
    logs: [],
    austria_logs: [],
    austria_sessions: [],
    notes: [],
    austria: { total_seconds: 0, is_active: false, last_start_timestamp: null },
    settings: { rate_per_km: 0.12, language: 'en' }
  };

  db.serialize(() => {
    // Get Settings
    db.get(`SELECT rate_per_km, language FROM users WHERE id = ?`, [userId], (err, row) => {
      if (row) {
        response.settings.rate_per_km = row.rate_per_km;
        response.settings.language = row.language || 'en';
      }
    });

    // Get Notes (Active or Future)
    db.all(`SELECT * FROM notes WHERE user_id = ? ORDER BY reminder_date ASC`, [userId], (err, rows) => {
      response.notes = rows || [];
    });

    // Get Today's Austria Status
    db.get(`SELECT * FROM austria_logs WHERE user_id = ? AND date = ?`, [userId, today], (err, row) => {
      if (row) {
        response.austria = {
          total_seconds: row.total_seconds,
          is_active: !!row.is_active,
          last_start_timestamp: row.last_start_timestamp
        };
      }
    });

    // Get Recent Austria Logs
    db.all(`SELECT * FROM austria_logs WHERE user_id = ? ORDER BY date DESC LIMIT 90`, [userId], (err, rows) => {
      response.austria_logs = rows || [];
    });

    // Get Recent Austria Sessions
    db.all(`SELECT * FROM austria_sessions WHERE user_id = ? ORDER BY start_time DESC LIMIT 200`, [userId], (err, rows) => {
      response.austria_sessions = rows || [];
    });

    // Get Recent Earnings Logs
    db.all(`SELECT * FROM daily_logs WHERE user_id = ? ORDER BY date DESC LIMIT 90`, [userId], (err, rows) => {
      response.logs = rows || [];
      res.json(response);
    });
  });
});

// Update Settings (Rate & Language)
app.post('/api/settings', authenticateToken, (req, res) => {
  const { rate_per_km, language } = req.body;

  if (rate_per_km !== undefined) {
    db.run(`UPDATE users SET rate_per_km = ? WHERE id = ?`, [rate_per_km, req.user.id]);
  }

  if (language !== undefined) {
    db.run(`UPDATE users SET language = ? WHERE id = ?`, [language, req.user.id]);
  }

  res.json({ success: true });
});

// Notes Routes
app.post('/api/notes', authenticateToken, (req, res) => {
  const { content, reminder_date } = req.body;
  db.run(`INSERT INTO notes (user_id, content, reminder_date) VALUES (?, ?, ?)`, 
    [req.user.id, content, reminder_date], (err) => {
      if(err) return res.status(500).json({error: err.message});
      res.json({success: true});
  });
});

app.delete('/api/notes/:id', authenticateToken, (req, res) => {
  db.run(`DELETE FROM notes WHERE id = ? AND user_id = ?`, [req.params.id, req.user.id], (err) => {
    if(err) return res.status(500).json({error: err.message});
    res.json({success: true});
  });
});

// Add or Update Daily Log
app.post('/api/logs', authenticateToken, (req, res) => {
  const { id, date, start_km, end_km, wage, total_earnings } = req.body;

  if (id) {
    db.run(`UPDATE daily_logs SET start_km=?, end_km=?, wage=?, total_earnings=? WHERE id=? AND user_id=?`,
      [start_km, end_km, wage, total_earnings, id, req.user.id], (err) => {
        if (err) return res.status(500).json({error: err.message});
        res.json({ success: true });
      });
  } else {
    db.get(`SELECT id FROM daily_logs WHERE user_id = ? AND date = ?`, [req.user.id, date], (err, row) => {
      if (row) {
        db.run(`UPDATE daily_logs SET start_km=?, end_km=?, wage=?, total_earnings=? WHERE id=?`,
          [start_km, end_km, wage, total_earnings, row.id], (err) => {
            if (err) return res.status(500).json({error: err.message});
            res.json({ success: true });
          });
      } else {
        db.run(`INSERT INTO daily_logs (user_id, date, start_km, end_km, wage, total_earnings) VALUES (?,?,?,?,?,?)`,
          [req.user.id, date, start_km, end_km, wage, total_earnings], (err) => {
            if (err) return res.status(500).json({error: err.message});
            res.json({ success: true });
          });
      }
    });
  }
});

// Toggle Austria
app.post('/api/austria/toggle', authenticateToken, (req, res) => {
  const today = new Date().toISOString().split('T')[0];
  const now = Date.now();
  const userId = req.user.id;

  db.get(`SELECT * FROM austria_logs WHERE user_id = ? AND date = ?`, [userId, today], (err, row) => {
    if (!row) {
      db.run(`INSERT INTO austria_logs (user_id, date, total_seconds, is_active, last_start_timestamp) VALUES (?, ?, 0, 1, ?)`,
        [userId, today, now], (err) => res.json({ success: true, is_active: true, total_seconds: 0 }));
    } else {
      if (row.is_active) {
        const startTime = row.last_start_timestamp;
        const duration = Math.floor((now - startTime) / 1000);
        const newTotal = row.total_seconds + duration;

        db.run(`UPDATE austria_logs SET total_seconds = ?, is_active = 0, last_start_timestamp = NULL WHERE id = ?`,
          [newTotal, row.id], (err) => {
            db.run(`INSERT INTO austria_sessions (user_id, start_time, end_time, duration, date) VALUES (?, ?, ?, ?, ?)`,
              [userId, startTime, now, duration, today], (err2) => {
                res.json({ success: true, is_active: false, total_seconds: newTotal });
              });
          });
      } else {
        db.run(`UPDATE austria_logs SET is_active = 1, last_start_timestamp = ? WHERE id = ?`,
          [now, row.id], (err) => res.json({ success: true, is_active: true, total_seconds: row.total_seconds }));
      }
    }
  });
});

app.get('*', (req, res) => {
