import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Settings, 
  LogOut,
  CalendarCheck,
  TrendingUp,
  MapPin,
  RefreshCw,
  Clock,
  CheckCircle2
} from 'lucide-react';
import { SmartCard, FilterType } from './components/SmartCard'; 
import { StatCard } from './components/StatCard'; 
import { RevenueChart } from './components/RevenueChart';
import { RecentActivity } from './components/RecentActivity';
import { AustriaControls } from './components/AustriaControls';
import { DailyLog } from './components/DailyLog';
import { SettingsView } from './components/SettingsView';
import { ProfileView } from './components/ProfileView';
import { NotesView } from './components/NotesView'; 
import { BottomNav } from './components/BottomNav';
import { LandingPage } from './components/LandingPage';
import { formatCurrency, formatDuration } from './utils/formatters';
import { Language, getTranslation } from './utils/translations';

type ViewType = 'dashboard' | 'history' | 'settings' | 'profile' | 'notes';

const App: React.FC = () => {
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [username, setUsername] = useState<string>(localStorage.getItem('username') || 'Driver');
  const [language, setLanguage] = useState<Language>((localStorage.getItem('language') as Language) || 'en');

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  // Data State
  const [ratePerKm, setRatePerKm] = useState(0.12);
  const [logs, setLogs] = useState<any[]>([]);
  const [austriaLogs, setAustriaLogs] = useState<any[]>([]); 
  const [austriaSessions, setAustriaSessions] = useState<any[]>([]); 
  const [notes, setNotes] = useState<any[]>([]);

  const [austriaState, setAustriaState] = useState({
    total_seconds: 0,
    is_active: false,
    last_start_timestamp: null as number | null
  });

  const [currentSessionSeconds, setCurrentSessionSeconds] = useState(0);

  // Filters
  const [earningsFilter, setEarningsFilter] = useState<FilterType>('today');
  const [earningsCustomRange, setEarningsCustomRange] = useState({ start: '', end: '' });

  const [austriaFilter, setAustriaFilter] = useState<FilterType>('today');
  const [austriaCustomRange, setAustriaCustomRange] = useState({ start: '', end: '' });

  // Helpers
  const t = (key: any) => getTranslation(language, key);
  const todayStr = new Date().toISOString().split('T')[0];
  const hasNotesToday = notes.some(n => n.reminder_date === todayStr);

  const handleLogin = (newToken: string, user: string, lang: Language) => {
    localStorage.setItem('token', newToken);
    localStorage.setItem('username', user);
    localStorage.setItem('language', lang);
    setToken(newToken);
    setUsername(user);
    setLanguage(lang);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('username');
    localStorage.removeItem('language');
    setToken(null);
  };

  const handleUpdateLanguage = async (lang: Language) => {
    setLanguage(lang);
    localStorage.setItem('language', lang);
    if(token) {
        await fetch('/api/settings', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
            body: JSON.stringify({ language: lang })
        });
    }
  };

  // Fetch Data
  const fetchData = async () => {
    if (!token) return;
    setIsLoading(true);
    try {
      const res = await fetch('/api/data', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.status === 401 || res.status === 403) {
        handleLogout();
        return;
      }
      const data = await res.json();
      setRatePerKm(data.settings.rate_per_km);
      if(data.settings.language) setLanguage(data.settings.language);

      setLogs(data.logs);
      setAustriaLogs(data.austria_logs || []); 
      setAustriaSessions(data.austria_sessions || []); 
      setNotes(data.notes || []);
      setAustriaState(data.austria);

      if (data.austria.is_active && data.austria.last_start_timestamp) {
        setCurrentSessionSeconds(Math.floor((Date.now() - data.austria.last_start_timestamp) / 1000));
      } else {
        setCurrentSessionSeconds(0);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (token) fetchData();
  }, [token]);

  useEffect(() => {
    let interval: number;
    if (austriaState.is_active && austriaState.last_start_timestamp) {
      interval = window.setInterval(() => {
        setCurrentSessionSeconds(Math.floor((Date.now() - (austriaState.last_start_timestamp as number)) / 1000));
      }, 1000);
    } else {
      setCurrentSessionSeconds(0);
    }
    return () => clearInterval(interval);
  }, [austriaState]);

  // Actions
  const updateSettings = async (newRate: number) => {
    try {
      await fetch('/api/settings', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({ rate_per_km: newRate })
      });
      setRatePerKm(newRate);
    } catch (err) {
      console.error(err);
    }
  };

  const toggleAustria = async () => {
    try {
      const res = await fetch('/api/austria/toggle', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      setAustriaState({
        total_seconds: data.total_seconds,
        is_active: data.is_active,
        last_start_timestamp: data.is_active ? Date.now() : null
      });
      if (!data.is_active) setCurrentSessionSeconds(0);
      setTimeout(fetchData, 100); 
    } catch (err) { console.error(err); }
  };

  const handleDailyLogSave = async (data: any) => {
     try {
       await fetch('/api/logs', {
         method: 'POST',
         headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`},
         body: JSON.stringify({ date: todayStr, ...data })
       });
       fetchData();
     } catch (err) { throw err; }
  };

  const handleLogUpdate = async (updatedLog: any) => {
    try {
       const dist = Math.max(0, updatedLog.end_km - updatedLog.start_km);
       const newTotal = (dist * ratePerKm) + updatedLog.wage;
       await fetch('/api/logs', {
         method: 'POST',
         headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`},
         body: JSON.stringify({ ...updatedLog, total_earnings: newTotal })
       });
       fetchData();
    } catch (err) { alert('Failed'); }
  };

  const handleDeleteLog = async (id: number) => {
      if (!confirm(t('confirm') + '?')) return;
      await fetch(`/api/logs/${id}`, {
          method: 'DELETE',
          headers: {'Authorization': `Bearer ${token}`}
      });
      fetchData();
  };

  const handleAddNote = async (content: string, date: string) => {
      await fetch('/api/notes', {
          method: 'POST',
          headers: {'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`},
          body: JSON.stringify({ content, reminder_date: date })
      });
      fetchData();
  };

  const handleDeleteNote = async (id: number) => {
      await fetch(`/api/notes/${id}`, {
          method: 'DELETE',
          headers: {'Authorization': `Bearer ${token}`}
      });
      fetchData();
  };

  const handleDeleteAustriaSession = async (id: number) => {
      if (!confirm(t('confirm') + '?')) return;
      await fetch(`/api/austria/session/${id}`, {
          method: 'DELETE',
          headers: {'Authorization': `Bearer ${token}`}
      });
      fetchData();
  }

  // Calculations (Simplified)
  const isDateInMonth = (dateStr: string) => {
    const d = new Date(dateStr); const now = new Date();
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  };
  const isDateInRange = (dateStr: string, start: string, end: string) => {
    if (!start || !end) return false;
    const d = new Date(dateStr).getTime(); const s = new Date(start).getTime(); const e = new Date(end).getTime();
    return d >= s && d <= e;
  };
  const isToday = (dateStr: string) => dateStr === todayStr;

  const getDisplayedEarnings = () => {
    if (earningsFilter === 'today') return logs.find(l => isToday(l.date))?.total_earnings || 0;
    if (earningsFilter === 'month') return logs.filter(l => isDateInMonth(l.date)).reduce((sum, l) => sum + l.total_earnings, 0);
    if (earningsFilter === 'custom') return logs.filter(l => isDateInRange(l.date, earningsCustomRange.start, earningsCustomRange.end)).reduce((sum, l) => sum + l.total_earnings, 0);
    return 0;
  };

  const getDisplayedAustriaTime = () => {
    if (austriaFilter === 'today') return austriaState.total_seconds + currentSessionSeconds;
    const historicalSum = austriaLogs.filter(log => {
        if (log.date === todayStr) return false;
        if (austriaFilter === 'month') return isDateInMonth(log.date);
        if (austriaFilter === 'custom') return isDateInRange(log.date, austriaCustomRange.start, austriaCustomRange.end);
        return false;
      }).reduce((acc, curr) => acc + curr.total_seconds, 0);
    let addToday = austriaFilter === 'month' || (austriaFilter === 'custom' && isDateInRange(todayStr, austriaCustomRange.start, austriaCustomRange.end));
    return historicalSum + (addToday ? (austriaState.total_seconds + currentSessionSeconds) : 0);
  };

  if (!token) return <LandingPage onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900 pb-20 lg:pb-0">

      {/* Sidebar (Desktop) */}
      <aside className="hidden lg:flex fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white flex-col shadow-2xl">
        <div className="h-24 flex items-center px-8 border-b border-slate-800">
           <div>
             <h1 className="text-2xl font-black tracking-tighter text-white">MASTNAK</h1>
             <p className="text-xs text-slate-400 font-medium tracking-widest uppercase">Driver Intelligence</p>
           </div>
        </div>
        <nav className="flex-1 px-4 py-8 space-y-2">
          <NavItem icon={<LayoutDashboard size={20} />} label={t('dashboard')} active={currentView === 'dashboard'} onClick={() => setCurrentView('dashboard')} />
          <NavItem icon={<CheckCircle2 size={20} />} label={t('notes')} active={currentView === 'notes'} onClick={() => setCurrentView('notes')} hasDot={hasNotesToday} />
          <NavItem icon={<Wallet size={20} />} label={t('history')} active={currentView === 'history'} onClick={() => setCurrentView('history')} />
          <NavItem icon={<Settings size={20} />} label={t('settings')} active={currentView === 'settings'} onClick={() => setCurrentView('settings')} />
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900/50">
          <button onClick={() => setCurrentView('profile')} className="flex items-center gap-3 w-full hover:bg-slate-800 p-2 rounded-xl transition-colors text-left">
             <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold text-lg shadow-lg">
                {username.charAt(0).toUpperCase()}
             </div>
             <div>
                <p className="font-bold text-sm text-white">{username}</p>
                <p className="text-xs text-slate-400">{t('profile')}</p>
             </div>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:ml-64">
        <header className="h-16 lg:h-20 bg-white/60 backdrop-blur-md flex items-center justify-between px-4 lg:px-10 shrink-0 sticky top-0 z-20 border-b border-white/50">
          <div className="flex items-center gap-3">
             <div className="lg:hidden w-8 h-8 bg-slate-900 rounded-lg flex items-center justify-center text-white font-bold text-xs">M</div>
             <h2 className="text-lg lg:text-xl font-bold text-slate-800">
               {t(currentView === 'dashboard' ? 'dashboard' : currentView === 'history' ? 'history' : currentView === 'profile' ? 'profile' : currentView === 'notes' ? 'notes' : 'settings')}
             </h2>
          </div>
          {currentView !== 'profile' && (
            <div className="flex items-center space-x-4">
               <button onClick={fetchData} className="p-2 text-slate-400 hover:text-slate-900 transition-colors rounded-full hover:bg-white">
                 <RefreshCw size={20} className={isLoading ? "animate-spin" : ""} />
               </button>
               <div className="hidden md:flex items-center gap-2 text-sm font-bold text-slate-600 bg-white/50 px-4 py-2 rounded-full border border-slate-200 shadow-sm">
                  <CalendarCheck size={16} className="text-indigo-500" />
                  <span>{new Date().toLocaleDateString(language === 'en' ? 'en-US' : language === 'de' ? 'de-DE' : language === 'bs' ? 'bs-BA' : 'it-IT', { weekday: 'short', day: '2-digit', month: 'long' })}</span>
               </div>
            </div>
          )}
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-8 scrollbar-hide">
          <div className="max-w-7xl mx-auto space-y-6 pb-24">

            {currentView === 'dashboard' && (
              <>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  <SmartCard title={t('earnings')} value={formatCurrency(getDisplayedEarnings())} icon={<Wallet className="text-indigo-600" />} filterType={earningsFilter} onFilterChange={setEarningsFilter} customRange={earningsCustomRange} onCustomRangeChange={(s, e) => setEarningsCustomRange({ start: s, end: e })} trendUp={true} />
                  <SmartCard title={t('austriaTime')} value={formatDuration(getDisplayedAustriaTime())} icon={<Clock className="text-rose-600" />} filterType={austriaFilter} onFilterChange={setAustriaFilter} customRange={austriaCustomRange} onCustomRangeChange={(s, e) => setAustriaCustomRange({ start: s, end: e })} subtitle={austriaState.is_active ? t('recording') : t('idle')} />
                  <StatCard title={t('currentRate')} value={`${formatCurrency(ratePerKm)}/km`} icon={<MapPin className="text-emerald-600" />} subtitle={t('config')} />
                </div>
                <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                  <div className="xl:col-span-2 space-y-6">
                     <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                       <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2"><TrendingUp size={20} className="text-slate-400" /> Revenue Analytics</h3>
                       <div className="h-[280px] w-full"><RevenueChart data={logs} /></div>
                     </div>
                  </div>
                  <div className="flex flex-col gap-6">
                    <AustriaControls isInsideAustria={austriaState.is_active} currentSessionTime={currentSessionSeconds} onToggle={toggleAustria} />
                    <DailyLog ratePerKm={ratePerKm} onSave={handleDailyLogSave} />
                  </div>
                </div>
              </>
            )}

            {currentView === 'history' && <RecentActivity logs={logs} austriaSessions={austriaSessions} onUpdateLog={handleLogUpdate} onDeleteLog={handleDeleteLog} onDeleteAustriaSession={handleDeleteAustriaSession} lang={language} />}
            {currentView === 'settings' && <SettingsView ratePerKm={ratePerKm} setRatePerKm={updateSettings} language={language} setLanguage={handleUpdateLanguage} />}
            {currentView === 'profile' && <ProfileView username={username} ratePerKm={ratePerKm} onLogout={handleLogout} onBack={() => setCurrentView('dashboard')} lang={language} />}
            {currentView === 'notes' && <NotesView notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} lang={language} />}
          </div>
        </div>
      </main>

      <BottomNav currentView={currentView} onChangeView={setCurrentView} username={username} hasNotification={hasNotesToday} />
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode; label: string; active?: boolean; onClick: () => void; hasDot?: boolean }> = ({ icon, label, active, onClick, hasDot }) => (
  <button onClick={onClick} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl text-sm font-bold transition-all duration-200 relative ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {icon} <span>{label}</span>
    {hasDot && <span className="absolute right-4 top-1/2 -translate-y-1/2 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>}
  </button>
);

export default App;

import React, { useState, useMemo } from 'react';
import { 
  CalendarCheck, 
  Wallet, 
  Clock, 
  ChevronLeft, 
  ChevronRight, 
  Filter, 
  Edit2, 
  Check, 
  X,
  MapPin,
  Calendar,
  ListFilter,
  Trash2
} from 'lucide-react';
import { formatCurrency, formatDuration } from '../utils/formatters';
import { CustomDatePicker } from './CustomDatePicker';
import { Language } from '../utils/translations';

interface Log {
  id: number;
  date: string;
  start_km: number;
  end_km: number;
  wage: number;
  total_earnings: number;
}

interface AustriaSession {
  id: number;
  date: string;
  start_time: number;
  end_time: number;
  duration: number;
}

interface RecentActivityProps {
  logs: Log[];
  austriaSessions: AustriaSession[];
  onUpdateLog?: (log: Log) => void;
  onDeleteLog?: (id: number) => void;
  onDeleteAustriaSession?: (id: number) => void;
  lang?: Language; // Add language prop for datepicker
}

type TabType = 'earnings' | 'austria';

export const RecentActivity: React.FC<RecentActivityProps> = ({ logs, austriaSessions, onUpdateLog, onDeleteLog, onDeleteAustriaSession, lang = 'en' }) => {
  const [activeTab, setActiveTab] = useState<TabType>('earnings');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Filter State - Default EMPTY to show all
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');

  // Editing State (Earnings)
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<Partial<Log>>({});

  // --- Helpers ---

  const isDateInRange = (dateStr: string) => {
    if (!dateFrom && !dateTo) return true; // Show all if no filter
    const d = new Date(dateStr).getTime();
    const from = dateFrom ? new Date(dateFrom).getTime() : -Infinity;
    const to = dateTo ? new Date(dateTo).getTime() : Infinity;
    return d >= from && d <= to;
  };

  // --- Filtering & Sorting Data ---

  const filteredLogs = useMemo(() => {
    return logs
      .filter(l => isDateInRange(l.date))
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [logs, dateFrom, dateTo]);

  const filteredAustria = useMemo(() => {
    return austriaSessions
      .filter(s => isDateInRange(s.date))
      .sort((a, b) => b.start_time - a.start_time);
  }, [austriaSessions, dateFrom, dateTo]);

  const currentData = activeTab === 'earnings' ? filteredLogs : filteredAustria;

  // --- Summaries ---

  const totalEarningsSummary = useMemo(() => {
    return filteredLogs.reduce((sum, log) => sum + log.total_earnings, 0);
  }, [filteredLogs]);

  const totalAustriaTimeSummary = useMemo(() => {
    return filteredAustria.reduce((sum, s) => sum + s.duration, 0);
  }, [filteredAustria]);

  // --- Pagination ---

  const totalPages = Math.ceil(currentData.length / itemsPerPage);
  const paginatedData = currentData.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handlePageChange = (p: number) => {
    if (p >= 1 && p <= totalPages) setCurrentPage(p);
  };

  // --- Edit Handlers ---

  const startEdit = (log: Log) => {
    setEditingId(log.id);
    setEditForm({ ...log });
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEdit = () => {
    if (onUpdateLog && editForm.id && editForm.start_km !== undefined && editForm.end_km !== undefined && editForm.wage !== undefined) {
      onUpdateLog({
        ...editForm as Log,
        total_earnings: 0 
      });
      setEditingId(null);
    }
  };

  // --- Render Row ---

  const renderDaySeparator = (currDate: string, prevDate: string | null) => {
    if (currDate !== prevDate) {
      return (
        <div className="flex items-center gap-4 py-4 mt-2">
          <div className="h-px bg-slate-200 flex-1"></div>
          <span className="text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 px-3 py-1 rounded-full border border-slate-100">
            {new Date(currDate).toLocaleDateString(lang === 'de' ? 'de-DE' : lang === 'bs' ? 'bs-BA' : lang === 'it' ? 'it-IT' : 'en-US', { weekday: 'short', day: '2-digit', month: 'short' })}
          </span>
          <div className="h-px bg-slate-200 flex-1"></div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">

      {/* Controls & Summary Header */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-5">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          {/* Tabs */}
          <div className="flex bg-slate-100 p-1 rounded-xl w-full md:w-auto">
            <button
              onClick={() => { setActiveTab('earnings'); setCurrentPage(1); }}
              className={`flex-1 md:w-32 py-2 px-4 rounded-lg text-sm font-bold transition-all ${
                activeTab === 'earnings' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Earnings
            </button>
            <button
              onClick={() => { setActiveTab('austria'); setCurrentPage(1); }}
              className={`flex-1 md:w-32 py-2 px-4 rounded-lg text-sm font-bold transition-all ${
                activeTab === 'austria' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Austria Time
            </button>
          </div>

          {/* Date Filter */}
          <div className="flex items-center gap-2">
             <div className="w-32">
                <CustomDatePicker value={dateFrom} onChange={setDateFrom} lang={lang} />
             </div>
             <span className="text-slate-300">-</span>
             <div className="w-32">
                <CustomDatePicker value={dateTo} onChange={setDateTo} lang={lang} />
             </div>
          </div>
        </div>

        {/* Dynamic Summary based on Filter */}
        <div className="pt-4 border-t border-slate-100">
           {activeTab === 'earnings' ? (
             <div className="flex justify-between items-center">
                <span className="text-sm text-slate-500 font-medium">Total Earnings {dateFrom || dateTo ? '(Selected)' : '(All Time)'}</span>
                <span className="text-xl font-black text-slate-900">{formatCurrency(totalEarningsSummary)}</span>
             </div>
           ) : (
             <div className="flex justify-between items-center">
                <span className="text-sm text-slate-500 font-medium">Total Austria Time {dateFrom || dateTo ? '(Selected)' : '(All Time)'}</span>
                <span className="text-xl font-black text-slate-900">{formatDuration(totalAustriaTimeSummary)}</span>
             </div>
           )}
        </div>
      </div>

      {/* Main List */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 min-h-[400px] flex flex-col">
        {paginatedData.length === 0 ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 py-12">
            <ListFilter size={48} className="mb-4 opacity-20" />
            <p>No records found.</p>
          </div>
        ) : (
          <div className="flex-1">
             {paginatedData.map((item, index) => {
               // Determine separation
               const prevItem = index > 0 ? paginatedData[index - 1] : null;
               const separator = renderDaySeparator(item.date, prevItem ? prevItem.date : null);

               if (activeTab === 'earnings') {
                 const log = item as Log;
                 const isEditing = editingId === log.id;

                 return (
                   <div key={log.id}>
                     {separator}
                     <div className={`p-4 rounded-xl transition-all ${isEditing ? 'bg-indigo-50 border border-indigo-100 shadow-sm' : 'hover:bg-slate-50 border border-transparent'}`}>
                        {isEditing ? (
                          // EDIT MODE
                          <div className="space-y-3">
                             <div className="flex justify-between items-center mb-2">
                               <span className="text-xs font-bold text-indigo-600 uppercase">Editing Entry</span>
                               <button onClick={cancelEdit} className="text-slate-400 hover:text-slate-600"><X size={16}/></button>
                             </div>
                             <div className="grid grid-cols-3 gap-3">
                                <div>
                                  <label className="text-[10px] text-slate-500 font-bold">Start KM</label>
                                  <input 
                                    type="number" 
                                    value={editForm.start_km} 
                                    onChange={(e) => setEditForm({...editForm, start_km: parseFloat(e.target.value)})}
                                    className="w-full p-2 rounded border border-indigo-200 text-sm"
                                  />
                                </div>
                                <div>
                                  <label className="text-[10px] text-slate-500 font-bold">End KM</label>
                                  <input 
                                    type="number" 
                                    value={editForm.end_km} 
                                    onChange={(e) => setEditForm({...editForm, end_km: parseFloat(e.target.value)})}
                                    className="w-full p-2 rounded border border-indigo-200 text-sm"
                                  />
                                </div>
                                <div>
                                  <label className="text-[10px] text-slate-500 font-bold">Wage (€)</label>
                                  <input 
                                    type="number" 
                                    value={editForm.wage} 
                                    onChange={(e) => setEditForm({...editForm, wage: parseFloat(e.target.value)})}
                                    className="w-full p-2 rounded border border-indigo-200 text-sm"
                                  />
                                </div>
                             </div>
                             <button onClick={saveEdit} className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2">
                               <Check size={16} /> Save Changes
                             </button>
                          </div>
                        ) : (
                          // VIEW MODE
                          <div className="flex justify-between items-center group">
                             <div className="flex items-center gap-4">
                                <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500">
                                   <Wallet size={18} />
                                </div>
                                <div>
                                   <p className="font-bold text-slate-900 text-sm">
                                     Route: <span className="font-mono text-slate-600">{log.start_km} ➝ {log.end_km} km</span>
                                   </p>
                                   <p className="text-xs text-slate-400">
                                     Dist: {log.end_km - log.start_km} km • Wage: €{log.wage}
                                   </p>
                                </div>
                             </div>

                             <div className="flex items-center gap-4">
                               <div className="text-right">
                                  <div className="font-black text-slate-900">{formatCurrency(log.total_earnings)}</div>
                               </div>
                               <div className="flex gap-1">
                                 <button 
                                   onClick={() => startEdit(log)}
                                   className="opacity-0 group-hover:opacity-100 p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                 >
                                   <Edit2 size={16} />
                                 </button>
                                 <button 
                                   onClick={() => onDeleteLog && onDeleteLog(log.id)}
                                   className="opacity-0 group-hover:opacity-100 p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
                                 >
                                   <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                          </div>
                        )}
                     </div>
                   </div>
                 );
               } else {
                 const session = item as AustriaSession;
                 return (
                   <div key={session.id}>
                     {separator}
                     <div className="p-4 rounded-xl hover:bg-slate-50 border border-transparent flex justify-between items-center group">
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 rounded-full bg-rose-50 flex items-center justify-center text-rose-500">
                              <MapPin size={18} />
                           </div>
                           <div>
                              <div className="flex items-center gap-2 text-sm font-bold text-slate-900">
                                <Clock size={14} className="text-slate-400"/>
                                <span>
                                  {new Date(session.start_time).toLocaleTimeString('de-DE', {hour: '2-digit', minute:'2-digit'})} 
                                  {' - '}
                                  {new Date(session.end_time).toLocaleTimeString('de-DE', {hour: '2-digit', minute:'2-digit'})}
                                </span>
                              </div>
                              <p className="text-xs text-slate-400 mt-0.5">Austria Entry Session</p>
                           </div>
                        </div>
                        <div className="flex items-center gap-4">
                           <div className="font-mono font-bold text-slate-900">{formatDuration(session.duration)}</div>
                           <button 
                             onClick={() => onDeleteAustriaSession && onDeleteAustriaSession(session.id)}
                             className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                           >
                             <Trash2 size={16} />
                           </button>
                        </div>
                     </div>
                   </div>
                 );
               }
             })}
          </div>
        )}

        {/* Pagination Footer */}
        {totalPages > 1 && (
          <div className="mt-8 pt-4 border-t border-slate-100 flex items-center justify-center gap-2">
            <button 
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="p-2 text-slate-400 hover:text-slate-900 disabled:opacity-30"
            >
              <ChevronLeft size={20} />
            </button>

            {Array.from({ length: totalPages }, (_, i) => i + 1).map((p) => {
              if (
                p === 1 || 
                p === totalPages || 
                (p >= currentPage - 1 && p <= currentPage + 1)
              ) {
                return (
                  <button
                    key={p}
                    onClick={() => handlePageChange(p)}
                    className={`w-8 h-8 rounded-lg text-xs font-bold transition-all ${
                      currentPage === p 
                        ? 'bg-slate-900 text-white' 
                        : 'text-slate-500 hover:bg-slate-100'
                    }`}
                  >
                    {p}
                  </button>
                );
              } else if (
                (p === currentPage - 2 && p > 1) || 
                (p === currentPage + 2 && p < totalPages)
              ) {
                return <span key={p} className="text-slate-300 text-xs">...</span>;
              }
              return null;
            })}

            <button 
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="p-2 text-slate-400 hover:text-slate-900 disabled:opacity-30"
            >
              <ChevronRight size={20} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
};
